import{_ as e,o as a,c as d,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Relay Subscriptions and In-App Purchases","description":"","frontmatter":{"title":"Relay Subscriptions and In-App Purchases","slug":"relay-subscriptions-and-in-app-purchases"},"headers":[],"relativePath":"developer-hub/relay-subscriptions-and-in-app-purchases.md","filePath":"developer-hub/relay-subscriptions-and-in-app-purchases.md"}'),i={name:"developer-hub/relay-subscriptions-and-in-app-purchases.md"};function r(s,t,n,c,h,p){return a(),d("div",null,[...t[0]||(t[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Unlike other <a href="./create-branch-objects-and-events.html">Branch Events</a>, you can log app store subscriptions and in-app purchases (IAPs) without needing to populate the Branch Event with transaction data yourself (although you still have that <a href="./track-branch-events.html#track-commerce-events">option</a> as well).</p><p>Instead, the Branch iOS and Android SDKs include methods that turn a standard app store purchase event into a Branch Event for you. This simplifies your code and reduces development overhead for your team.</p><p>When you pass Branch a standard purchase event, we log a Branch <code>PURCHASE</code> Event in our system for that transaction.</p><p>Branch recommends that customers implement validation checking within their systems for these app store transactions, which can be done either on-device or server-side using APIs provided by <a href="https://developer.apple.com/documentation/storekit/in-app_purchase/original_api_for_in-app_purchase/choosing_a_receipt_validation_technique" target="_blank" rel="noreferrer">Apple</a> and <a href="https://developer.android.com/google/play/billing/security" target="_blank" rel="noreferrer">Google</a>.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>To relay subscriptions and IAPs to Branch for event mapping, you first need to:</p><ol><li>Create a <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</li><li>Integrate the appropriate Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>).</li></ol><h2 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h2><h3 id="ios" tabindex="-1">iOS <a class="header-anchor" href="#ios" aria-label="Permalink to &quot;iOS&quot;">​</a></h3><ol><li>Create a new Branch Event.</li></ol><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-K-W7c" id="tab-eEdq-wJ" checked><label data-title="Swift" for="tab-eEdq-wJ">Swift</label><input type="radio" name="group-K-W7c" id="tab-5Umx2a6"><label data-title="Objective-C" for="tab-5Umx2a6">Objective-C</label></div><div class="blocks"><div class="language-swift vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">swift</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> event </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> BranchEvent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;PURCHASE&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><div class="language-objectivec vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">objectivec</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BranchEvent *event = [[BranchEvent alloc] initWithName:@&quot;eventName&quot;];</span></span></code></pre></div></div></div><ol start="2"><li>Log the new Branch Event using the <code>logEvent</code> method, and pass that method an <code>SKPaymentTransaction</code> <a href="https://developer.apple.com/documentation/storekit/skpaymenttransaction" target="_blank" rel="noreferrer">object</a> that you&#39;ve fetched from the <a href="https://developer.apple.com/documentation/storekit" target="_blank" rel="noreferrer">Apple StoreKit API</a>.</li></ol><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-JYkyp" id="tab-jCRV1XS" checked><label data-title="Swift" for="tab-jCRV1XS">Swift</label><input type="radio" name="group-JYkyp" id="tab-RChO0Qd"><label data-title="Objective-C" for="tab-RChO0Qd">Objective-C</label></div><div class="blocks"><div class="language-swift vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">swift</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">event.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">logEvent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">with</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: transaction </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">as!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> SKPaymentTransaction)</span></span></code></pre></div><div class="language-objectivec vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">objectivec</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[event logEventWithTransaction:(SKPaymentTransaction *)transaction];</span></span></code></pre></div></div></div><h3 id="android" tabindex="-1">Android <a class="header-anchor" href="#android" aria-label="Permalink to &quot;Android&quot;">​</a></h3><ol><li>On Android, use the <a href="https://developers.google.com/android-publisher#subscriptions" target="_blank" rel="noreferrer">Google Play Developer API</a> to retrieve and pass a <code>Purchase</code> <a href="https://developer.android.com/reference/com/android/billingclient/api/Purchase" target="_blank" rel="noreferrer">object</a> to the Branch <code>logEventWithPurchase</code> method. This method is accessible directly from the global Branch instance.</li></ol><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-xiD2Q" id="tab-Qg8pmpU" checked><label data-title="Java" for="tab-Qg8pmpU">Java</label><input type="radio" name="group-xiD2Q" id="tab-S4o8K49"><label data-title="Kotlin" for="tab-S4o8K49">Kotlin</label></div><div class="blocks"><div class="language-java vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Branch.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getInstance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">().</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">logEventWithPurchase</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(MainActivity.this, (Purchase) purchase);</span></span></code></pre></div><div class="language-kotlin vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">kotlin</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Branch.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getInstance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">().</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">logEventWithPurchase</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, purchase);</span></span></code></pre></div></div></div><h2 id="object-mapping" tabindex="-1">Object Mapping <a class="header-anchor" href="#object-mapping" aria-label="Permalink to &quot;Object Mapping&quot;">​</a></h2><p>The Branch iOS and Android SDKs map transaction details from the Apple and Google APIs into a <code>BranchUniversalObject</code> and <code>BranchStandardEvent</code> for you, based on the tables in this section.</p><p>Note that <a href="./create-branch-objects-and-events.html">Branch Universal Objects</a> represent the thing you want to share (such as an article, video, or item for sale), and that <code>BUO</code> is an instance of <code>BranchUniversalObject</code>.</p><h4 id="ios-to-branch-basic-mapping" tabindex="-1">iOS to Branch Basic Mapping <a class="header-anchor" href="#ios-to-branch-basic-mapping" aria-label="Permalink to &quot;iOS to Branch Basic Mapping&quot;">​</a></h4><p>Branch uses the object you pass in for <code>transaction</code> to look up the <code>Product</code> object associated with it, and maps it in the following way:</p><table tabindex="0"><thead><tr><th>iOS</th><th>Branch</th></tr></thead><tbody><tr><td><code>Product.quantity</code></td><td><code>BUO.quantity</code></td></tr><tr><td><code>Product.description</code></td><td><code>BUO.description</code></td></tr><tr><td><code>Product.displayName</code></td><td><code>BUO.title</code></td></tr><tr><td><code>Product.price</code></td><td><code>BUO.price</code></td></tr><tr><td><code>Product.id</code></td><td><code>BUO.canonicalIdentifer</code></td></tr><tr><td><code>Product.type</code></td><td><code>BranchStandardEvent</code></td></tr></tbody></table><h4 id="android-to-branch-basic-mapping" tabindex="-1">Android to Branch Basic Mapping <a class="header-anchor" href="#android-to-branch-basic-mapping" aria-label="Permalink to &quot;Android to Branch Basic Mapping&quot;">​</a></h4><p>On Android, the <code>purchase</code> object you pass in is used to look up the <code>productId</code> and associated <code>productDetails</code>, and has the following mapping:</p><table tabindex="0"><thead><tr><th>Android</th><th>Branch</th></tr></thead><tbody><tr><td><code>Purchase.quantity</code></td><td><code>BUO.quantity</code></td></tr><tr><td><code>ProductDetails.description</code></td><td><code>BUO.description</code></td></tr><tr><td><code>ProductDetails.title</code></td><td><code>BUO.title</code></td></tr><tr><td><code>ProductDetails.formattedPrice</code></td><td><code>BUO.price</code></td></tr><tr><td><code>ProductDetails.productId</code></td><td><code>BUO.canonicalIdentifer</code></td></tr><tr><td><code>ProductDetails.productType</code></td><td><code>BranchStandardEvent</code></td></tr></tbody></table><h4 id="additional-object-mapping-on-ios-and-android" tabindex="-1">Additional Object Mapping on iOS and Android <a class="header-anchor" href="#additional-object-mapping-on-ios-and-android" aria-label="Permalink to &quot;Additional Object Mapping on iOS and Android&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Branch</th><th>iOS</th><th>Android</th></tr></thead><tbody><tr><td><code>BranchEvent.name</code></td><td><code>“Purchase”</code></td><td><code>“Purchase”</code></td></tr><tr><td><code>BranchEvent.Description</code></td><td><code>Transaction.Identifier</code></td><td><code>Purchase.OrderID</code></td></tr><tr><td><code>BranchEvent.Currency</code></td><td><code>Product.CurrencyCode</code></td><td><code>Product.CurrencyCode</code></td></tr><tr><td><code>BranchEvent.revenue</code></td><td><code>Product.Price</code></td><td><code>Product.Price</code> * <code>Transaction.Quantity</code></td></tr><tr><td><code>BUO.canonicalIdentifier</code></td><td><code>Product Identifier</code></td><td><code>Product.ProductID</code></td></tr><tr><td><code>BUO.title</code></td><td><code>Product.LocalizedTitle</code></td><td><code>Product.Title</code></td></tr><tr><td><code>BUO.price</code></td><td><code>Product.Price</code></td><td><code>Product.Price</code></td></tr><tr><td><code>BUO.currency</code></td><td><code>Product.CurrencyCode</code></td><td><code>Product.CurrencyCode</code></td></tr><tr><td><code>BUO.productName</code></td><td><code>Product.Title</code></td><td><code>Product.Name</code></td></tr><tr><td><code>BUO.contentDescription</code></td><td><code>Product.Description</code></td><td>N/A</td></tr><tr><td><code>BUO.quantity</code></td><td>1</td><td><code>Transaction.Quantity</code></td></tr><tr><td><code>BranchEvent.CustomerEventAlias</code></td><td><code>IAP</code> <strong>or</strong> <code>Subscription</code></td><td><code>“inapp”</code> <strong>or</strong> <code>”subs”</code></td></tr><tr><td><code>BranchEvent.CustomMetadata</code></td><td><code>@&quot;transaction_identifier&quot;: _transactionID,</code> <code>@&quot;logged_from_IAP&quot;: @true</code></td><td><code>(&quot;package_name&quot;, purchase.packageName) (&quot;order_id&quot;, purchase.orderId) (&quot;logged_from_IAP&quot;, &quot;true&quot;) (&quot;is_auto_renewing&quot;, purchase.isAutoRenewing.toString()) (&quot;purchase_token&quot;, purchase.purchaseToken)</code></td></tr><tr><td><code>BUO.CustomMetadata</code></td><td><code>@&quot;content_version&quot;: product.contentVersion</code> <code>@&quot;is_downloadable&quot;: @product.isDownloadable</code> <code>@&quot;is_family_shareable”:product.isFamilyShareable</code></td><td><code>(&quot;product_type&quot;, product.productType)</code></td></tr><tr><td><code>BranchEvent.ContentItems</code></td><td>N/A</td><td><code>ProductDetails</code> as <code>BUO</code></td></tr></tbody></table><h2 id="access-the-data" tabindex="-1">Access the Data <a class="header-anchor" href="#access-the-data" aria-label="Permalink to &quot;Access the Data&quot;">​</a></h2><p>Subscription and IAP event data is accessible the same way as data from other Branch Events. You can view and export the data via the <a href="./branch-dashboard-overview.html">Branch Dashboard</a>, as well as through our <a href="./overview.html">APIs</a>, by targeting <code>PURCHASE</code> Branch Events.</p><p>You can also use the Dashboard to configure the data to be sent to an ad network with a <a href="./postbacks.html">postback</a>.</p><p>To differentiate between subscription data and IAP data, filter your analytics by the <code>CustomerEventAlias</code> field, the values for which can be found in the &quot;Additional Object Mapping&quot; <a href="./relay-subscriptions-and-in-app-purchases.html#additional-object-mapping">table</a>.</p>',32)])])}const b=e(i,[["render",r]]);export{u as __pageData,b as default};
